function MaintenanceBoard({ tickets, onMoveTicket }) {
  const { div, h1, h2, span } = tags;
  const [view, setView] = createSignal('board');
  const [propertyFilter, setPropertyFilter] = createSignal('all');
  const [priorityFilter, setPriorityFilter] = createSignal('all');

  const columns = [
    { id: 'new', name: 'New', color: 'primary' },
    { id: 'assigned', name: 'Assigned', color: 'secondary' },
    { id: 'in-progress', name: 'In Progress', color: 'warning' },
    { id: 'pending-parts', name: 'Pending Parts', color: 'muted' },
    { id: 'completed', name: 'Completed', color: 'success' },
    { id: 'closed', name: 'Closed', color: 'default' }
  ];

  const filtered = () => tickets.filter(t => {
    if (propertyFilter() !== 'all' && t.propertyId !== propertyFilter()) return false;
    if (priorityFilter() !== 'all' && t.priority !== priorityFilter()) return false;
    return true;
  });

  const ticketsByColumn = (columnId) => filtered().filter(t => t.status === columnId);
  const openCount = filtered().filter(t => !['completed', 'closed'].includes(t.status)).length;

  const handleDragStart = (e, ticket) => {
    e.dataTransfer.setData('ticketId', ticket.id);
  };

  const handleDrop = (e, columnId) => {
    e.preventDefault();
    const ticketId = e.dataTransfer.getData('ticketId');
    onMoveTicket(ticketId, columnId);
  };

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      div({},
        h1({ class: css('_heading3') }, 'Maintenance'),
        span({ class: css('_textsm _fgmuted') }, `${openCount} open tickets`)
      ),
      div({ class: css('_flex _gap2') },
        div({ class: css('_flex _r1 _border _overflow[hidden]') },
          Button({ variant: view() === 'board' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('board') }, icon('columns')),
          Button({ variant: view() === 'list' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('list') }, icon('list'))
        ),
        Button({ variant: 'primary' }, icon('plus'), 'New Ticket')
      )
    ),
    div({ class: css('_flex _gap4 _aic') },
      Select({ value: propertyFilter(), onchange: e => setPropertyFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Properties')
        // Property options populated dynamically
      ),
      Select({ value: priorityFilter(), onchange: e => setPriorityFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Priorities'),
        tags.option({ value: 'emergency' }, 'Emergency'),
        tags.option({ value: 'high' }, 'High'),
        tags.option({ value: 'medium' }, 'Medium'),
        tags.option({ value: 'low' }, 'Low')
      )
    ),
    div({ class: css('_flex _gap4 _overflow[auto] _pb4 _minw[1200px]') },
      ...columns.map(col =>
        div({
          class: css('_flex _col _gap2 _minw[280px] _w[280px] _bgSurfaceRaised _r2 _p3'),
          ondragover: e => e.preventDefault(),
          ondrop: e => handleDrop(e, col.id)
        },
          div({ class: css('_flex _jcsb _aic _mb3') },
            span({ class: css('_font500') }, col.name),
            span({ class: css('_textsm _fgmuted _bgBorder _px2 _r1') }, ticketsByColumn(col.id).length)
          ),
          div({ class: css('_flex _col _gap2 _minH[200px]') },
            ...ticketsByColumn(col.id).map(ticket => TicketCard({ ticket, onDragStart: handleDragStart }))
          )
        )
      )
    )
  );
}

function TicketCard({ ticket, onDragStart }) {
  const { div, span, p } = tags;
  const priorityColor = ticket.priority === 'emergency' ? 'danger' : ticket.priority === 'high' ? 'warning' : 'default';

  return link({
    href: `/maintenance/${ticket.id}`,
    class: css('estate-card _p3 _cursor[grab] _hoverShadow _trans'),
    draggable: true,
    ondragstart: e => onDragStart(e, ticket)
  },
    div({ class: css('_flex _jcsb _aic _mb2') },
      span({ class: css('_textsm _font500') }, `#${ticket.id}`),
      Badge({ variant: priorityColor, size: 'sm' }, ticket.priority)
    ),
    p({ class: css('_textsm _mb2 _lineClamp[2]') }, ticket.description.slice(0, 80) + (ticket.description.length > 80 ? '...' : '')),
    div({ class: css('_flex _jcsb _aic') },
      Badge({ variant: 'outline', size: 'sm' }, ticket.category),
      span({ class: css('_textxs _fgmuted') }, `Unit ${ticket.unitNumber}`)
    )
  );
}

