function MaintenanceMini({ tickets }) {
  const { div, span } = tags;
  const newCount = tickets.filter(t => t.status === 'new').length;
  const inProgressCount = tickets.filter(t => t.status === 'in-progress').length;
  const completedCount = tickets.filter(t => t.status === 'completed').length;

  return link({ href: '/maintenance', class: css('estate-card _p4 _hoverShadow _trans') },
    div({ class: css('_flex _jcsb _aic _mb3') },
      span({ class: css('_heading6') }, 'Maintenance'),
      Badge({ variant: newCount > 0 ? 'warning' : 'success' }, `${newCount} new`)
    ),
    div({ class: css('_grid _cols3 _gap2') },
      div({ class: css('_tc') },
        span({ class: css('_heading4 _block') }, newCount),
        span({ class: css('_textxs _fgmuted') }, 'New')
      ),
      div({ class: css('_tc') },
        span({ class: css('_heading4 _block _fgwarning') }, inProgressCount),
        span({ class: css('_textxs _fgmuted') }, 'In Progress')
      ),
      div({ class: css('_tc') },
        span({ class: css('_heading4 _block _fgsuccess') }, completedCount),
        span({ class: css('_textxs _fgmuted') }, 'Completed')
      )
    )
  );
}

